package com.izonehub.stores.inventory;import org.junit.jupiter.api.Test;import java.math.BigDecimal;import static org.assertj.core.api.Assertions.*;class StoreInventoryTest{@Test void dispatchRequiresSufficientStockAndMovesToTransit(){StoreInventory inv=new StoreInventory(null,null);inv.receiveUsable(new BigDecimal("10"));inv.dispatch(new BigDecimal("4"));assertThat(inv.getQuantityOnHand()).isEqualByComparingTo("6");assertThat(inv.getQuantityInTransit()).isEqualByComparingTo("4");} @Test void cannotDispatchMoreThanOnHand(){StoreInventory inv=new StoreInventory(null,null);assertThatThrownBy(()->inv.dispatch(BigDecimal.ONE)).isInstanceOf(IllegalStateException.class);}}
